// // This module compresses a 5-bit signed input to a 5-bit signed output with a dynamic range reduction. Inputs below -2 or above 2 are mapped to 2 and -2 respectively, while inputs within the range [-2, 2] are passed through unchanged.
module dynamic_range_compressor(  
    input signed [4:0] in_signal,  
    output signed [4:0] out_signal  
);  
    assign out_signal = (in_signal < -2) ? -2 :  
                        (in_signal > 2) ? 2 :  
                        in_signal;  
endmodule
